 14	import MetricTypeDropdown from './metric-type-dropdown';
 15	import ScopeDropdown from './scope-dropdown';
 16	
 17	export type Size = 's' | 'm' | 'l';
 18	
 19	export interface TopologyDisplayOptionsProps {
 20	  metricFunction: StatFunction;
 21	  setMetricFunction: (f: StatFunction) => void;
 22	  metricType: MetricType;
 23	  setMetricType: (t: MetricType) => void;
 24	  metricScope: FlowScope;
 25	  setMetricScope: (s: FlowScope) => void;
 26	  topologyOptions: TopologyOptions;
 27	  setTopologyOptions: (o: TopologyOptions) => void;
 28	  allowedTypes: MetricType[];
 29	  scopes: ScopeConfigDef[];
 30	}
 31	
 32	export const TopologyDisplayOptions: React.FC<TopologyDisplayOptionsProps> = ({
 33	  metricFunction,
 34	  setMetricFunction,
 35	  metricType,
 36	  setMetricType,
 37	  metricScope,
 38	  setMetricScope,
 39	  topologyOptions,
 40	  setTopologyOptions,
 41	  allowedTypes,
 42	  scopes
 43	}) => {
 44	  const { t } = useTranslation('plugin__netobserv-plugin');
 45	
 46	  const setLayout = (layout: LayoutName) => {
 47	    setTopologyOptions({
 48	      ...topologyOptions,
 49	      layout
 50	    });
 51	  };
 52	
 53	  const setGroupType = (groupTypes: TopologyGroupTypes) => {
 54	    setTopologyOptions({
 55	      ...topologyOptions,
 56	      groupTypes
 57	    });
 58	  };
 59	
 60	  const setTruncateLength = (truncateLength: TruncateLength) => {
 61	    setTopologyOptions({
 62	      ...topologyOptions,
 63	      truncateLength
 64	    });
 65	  };
 66	
 67	  return (
 68	    <>
 69	      <div className="pf-v6-c-menu__group">
 70	        <Tooltip content={t('Measurement to show as edge labels.')}>
 71	          <div className="pf-v6-c-menu__group-title">
 72	            <Text component={TextVariants.p}>
 73	              {t('Edge labels')} <InfoAltIcon />
 74	            </Text>
 75	          </div>
 76	        </Tooltip>
 77	        <div className="display-dropdown-padding">
 78	          <Flex>
 79	            <FlexItem>
 80	              <MetricFunctionDropdown
 81	                data-test="metricFunction"
 82	                id="metricFunction"
 83	                selected={metricFunction}
 84	                setMetricFunction={setMetricFunction}
 85	                metricType={metricType}
 86	              />
 87	            </FlexItem>
 88	            <FlexItem>
 89	              <MetricTypeDropdown
 90	                data-test="metricType"
 91	                id="metricType"
 92	                selected={metricType}
 93	                setMetricType={setMetricType}
 94	                allowedTypes={allowedTypes}
 95	              />
 96	            </FlexItem>
 97	          </Flex>
 98	        </div>
 99	      </div>
100	      <div className="pf-v6-c-menu__group">
101	        <Tooltip content={t('The level of details represented.')}>
102	          <div className="pf-v6-c-menu__group-title">
103	            <Text component={TextVariants.p}>
104	              {t('Scope')} <InfoAltIcon />
105	            </Text>
106	          </div>
107	        </Tooltip>
108	        <div className="display-dropdown-padding">
109	          <ScopeDropdown
110	            data-test="scope"
111	            id="scope"
112	            selected={metricScope}
113	            setScopeType={setMetricScope}
114	            scopes={scopes}
115	          />
116	        </div>
117	      </div>
118	      <div className="pf-v6-c-menu__group">
119	        <Tooltip content={t('Grouping items helps to better understand ownership.')}>
120	          <div className="pf-v6-c-menu__group-title">
121	            <Text component={TextVariants.p}>
122	              {t('Groups')} <InfoAltIcon />
123	            </Text>
124	          </div>
125	        </Tooltip>
126	        <div className="display-dropdown-padding">
127	          <GroupDropdown
128	            id="group"
129	            disabled={metricScope === MetricScopeOptions.CLUSTER}
130	            scope={metricScope as MetricScopeOptions}
131	            selected={topologyOptions.groupTypes}
132	            setGroupType={setGroupType}
133	            scopes={scopes}
134	          />
135	        </div>
136	      </div>
137	      <div className="pf-v6-c-menu__group">
138	        <Tooltip content={t('The way in which topology items are arranged.')}>
139	          <div className="pf-v6-c-menu__group-title">
140	            <Text component={TextVariants.p}>
141	              {t('Layout')} <InfoAltIcon />
142	            </Text>
143	          </div>
144	        </Tooltip>
145	        <div className="display-dropdown-padding">
146	          <LayoutDropdown id="layout" selected={topologyOptions.layout} setLayout={setLayout} />
147	        </div>
148	      </div>
149	      <div className="pf-v6-c-menu__group">
150	        <Tooltip content={t('Various options to show / hide view details.')}>
151	          <div className="pf-v6-c-menu__group-title">
152	            <Text component={TextVariants.p}>
153	              {t('Show')} <InfoAltIcon />
154	            </Text>
155	          </div>
156	        </Tooltip>
157	        <div className="display-dropdown-padding">
158	          <Checkbox
159	            id="edges-switch"
160	            label={t('Edges')}
161	            isChecked={topologyOptions.edges}
162	            onChange={() =>
163	              setTopologyOptions({
164	                ...topologyOptions,
165	                edges: !topologyOptions.edges
166	              })
167	            }
168	          />
169	          <Checkbox
170	            id="edges-tag-switch"
171	            label={t('Edges label')}
172	            isDisabled={!topologyOptions.edges}
173	            isChecked={topologyOptions.edges && topologyOptions.edgeTags}
174	            onChange={() =>
175	              setTopologyOptions({
176	                ...topologyOptions,
177	                edgeTags: !topologyOptions.edgeTags
178	              })
179	            }
180	          />
181	          <Checkbox
182	            id="badge-switch"
183	            label={t('Badges')}
184	            isChecked={topologyOptions.nodeBadges}
185	            onChange={() =>
186	              setTopologyOptions({
187	                ...topologyOptions,
188	                nodeBadges: !topologyOptions.nodeBadges
189	              })
190	            }
191	          />
192	          <Checkbox
193	            id="empty-switch"
194	            label={t('Empty')}
195	            isChecked={topologyOptions.showEmpty}
196	            onChange={() =>
197	              setTopologyOptions({
198	                ...topologyOptions,
199	                showEmpty: !topologyOptions.showEmpty
200	              })
201	            }
202	          />
203	        </div>
204	      </div>
205	      <div className="pf-v6-c-menu__group">
206	        <Tooltip content={t('Long labels can reduce visibility.')}>
207	          <div className="pf-v6-c-menu__group-title">
208	            <Text component={TextVariants.p}>
209	              {t('Truncate labels')} <InfoAltIcon />
210	            </Text>
211	          </div>
212	        </Tooltip>
213	        <div className="display-dropdown-padding">
214	          <TruncateDropdown
215	            id="truncate"
216	            selected={topologyOptions.truncateLength}
217	            setTruncateLength={setTruncateLength}
218	          />
219	        </div>
220	      </div>
221	      <div className="pf-v6-c-menu__group">
222	        <div className="display-dropdown-switch-padding">
223	          <Switch
224	            id="group-collapsed-switch"
225	            label={t('Collapse groups')}
226	            isDisabled={topologyOptions.groupTypes === 'none'}
227	            isChecked={topologyOptions.groupTypes !== 'none' && topologyOptions.startCollapsed}
228	            onChange={() =>
229	              setTopologyOptions({
230	                ...topologyOptions,
231	                startCollapsed: !topologyOptions.startCollapsed
232	              })
233	            }
234	            isReversed
235	          />
236	        </div>
237	      </div>
238	    </>
239	  );
240	};
241	
242	export default TopologyDisplayOptions;

